for $r in SQL('
SELECT AREA_EST.oi_area_est as AREA_VAL, AREA_EST.d_area_est as AREA_DES, NIV_EST.oi_nivel_estudio as NIV_VAL, NIV_EST.d_nivel_estudio as NIV_DES, ESTU.oi_estudio as EST_VAL, ESTU.d_estudio as EST_DES, EST_PER.d_otro_est as OTRO, TIPO_EST.oi_tipo_establecim as TIPO_VAL, TIPO_EST.d_tipo_establecim as TIPO_DES, EST_PER.f_ini_estudio as FEC_INI, EST_PER.f_fin_estudio as FEC_FIN, ESTADO.oi_estado_est as ESTADO_VAL, ESTADO.d_estado_est as ESTADO_DES, PAIS.oi_pais as PAIS_VAL, PAIS.d_pais as PAIS_DES, EST_PER.l_est_extranjero as EST_EXT, EST_PER.d_otro_est_educ as EST_EDUC,EST_PER.e_duracion_estudio as DUR, UNI_TPO.oi_unidad_tiempo as TIEMPO_VAL, UNI_TPO.d_unidad_tiempo as TIEMPO_DES, EST_PER.e_periodo_en_curso as PER_CUR, EST_PER.e_mat_adeudadas as MAT_ADE, EST_PER.f_actualiz as FEC_ACT, EST_PER.n_promedio as PROM FROM PER01_ESTUDIOS_PER as EST_PER, ORG43_AREAS_EST as AREA_EST, PER12_NIVELES_EST as NIV_EST, ORG11_ESTUDIOS as ESTU, PER23_T_EST_EDUC as TIPO_EST, PER13_ESTADOS_EST as ESTADO, ORG35_PAISES as PAIS, ORG25_UNIDADES_TPO as UNI_TPO JOIN EST_PER.oi_area_est INNER AREA_EST.oi_area_est, EST_PER.oi_nivel_estudio INNER NIV_EST.oi_nivel_estudio, EST_PER.oi_estudio LEFT ESTU.oi_estudio, EST_PER.oi_tipo_establecim LEFT TIPO_EST.oi_tipo_establecim, EST_PER.oi_estado_est LEFT ESTADO.oi_estado_est, EST_PER.oi_pais LEFT PAIS.oi_pais, EST_PER.oi_unidad_tiempo LEFT UNI_TPO.oi_unidad_tiempo WHERE EST_PER.oi_estudio_per = {$FILTER/@oi_estudio_per}
')/ROWS/ROW
